import{_ as a,o,c as r,ag as i}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Relés de Sobrecarga","description":"","frontmatter":{},"headers":[],"relativePath":"es/control-panels/overload-relays.md","filePath":"es/control-panels/overload-relays.md"}'),n={name:"es/control-panels/overload-relays.md"};function c(t,e,l,s,d,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="reles-de-sobrecarga" tabindex="-1">Relés de Sobrecarga <a class="header-anchor" href="#reles-de-sobrecarga" aria-label="Permalink to &quot;Relés de Sobrecarga&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los relevadors de sobrecarga son dispositivos de protección utilizados para prevenir daños en motores causados por condiciones prolongadas de sobrecorriente.</p><p>Monitorean la corriente del motor y desconectan el circuito de control cuando la corriente excede los límites seguros durante un periodo de tiempo.</p><p>Normalmente se utilizan en conjunto con contactores en circuitos de control de motores.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de un relevador de sobrecarga es proteger los motores contra sobrecalentamiento y daños.</p><p>Se utiliza para:</p><ul><li>Detectar condiciones de sobrecorriente sostenida</li><li>Prevenir el sobrecalentamiento del motor</li><li>Proteger contra sobrecargas mecánicas</li><li>Extender la vida útil del motor</li></ul><p>Proporciona una protección que los interruptores automáticos por sí solos no pueden ofrecer.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los relevadors de sobrecarga monitorean la corriente y responden en función del tiempo y la magnitud.</p><h3 id="monitoreo-de-corriente" tabindex="-1">Monitoreo de corriente <a class="header-anchor" href="#monitoreo-de-corriente" aria-label="Permalink to &quot;Monitoreo de corriente&quot;">​</a></h3><p>El relevador mide la corriente que fluye hacia el motor.</p><ul><li>En operación normal se mantiene dentro de los límites establecidos</li><li>Las condiciones de sobrecarga incrementan la corriente con el tiempo</li></ul><p>El relevador evalúa tanto el nivel como la duración.</p><h3 id="mecanismo-de-disparo" tabindex="-1">Mecanismo de disparo <a class="header-anchor" href="#mecanismo-de-disparo" aria-label="Permalink to &quot;Mecanismo de disparo&quot;">​</a></h3><p>Cuando se detecta una condición de sobrecarga:</p><ul><li>El relevador dispara después de un tiempo definido</li><li>Abre el circuito de control del contactor</li><li>El contactor desconecta la energía al motor</li></ul><p>Esto detiene el motor antes de que ocurra daño.</p><h3 id="comportamiento-termico" tabindex="-1">Comportamiento térmico <a class="header-anchor" href="#comportamiento-termico" aria-label="Permalink to &quot;Comportamiento térmico&quot;">​</a></h3><p>Muchos relevadors de sobrecarga simulan el calentamiento del motor.</p><ul><li>Modelos térmicos siguen la acumulación de calor</li><li>El tiempo de disparo depende del nivel de corriente</li></ul><p>Esto se ajusta a las necesidades reales de protección del motor.</p><h3 id="funcion-de-reinicio" tabindex="-1">Función de reinicio <a class="header-anchor" href="#funcion-de-reinicio" aria-label="Permalink to &quot;Función de reinicio&quot;">​</a></h3><p>Después de un disparo:</p><ul><li>Se requiere un reinicio manual o automático</li><li>El motor no debe reiniciarse hasta resolver la causa</li></ul><p>El reinicio restablece la operación normal.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los relevadors de sobrecarga se utilizan en sistemas de control de motores.</p><p>Aplicaciones típicas incluyen:</p><ul><li>Bombas y compresores</li><li>Transportadores y equipos de producción</li><li>Ventiladores y sistemas HVAC</li><li>Sistemas accionados por motores en general</li></ul><p>Son esenciales para la protección de motores en entornos industriales.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>El ajuste del relevador debe coincidir con la corriente nominal del motor.</p><p>La clase de disparo debe adecuarse a las características de la aplicación.</p><p>La coordinación con contactores e interruptores automáticos es importante.</p><p>La temperatura ambiente puede afectar el desempeño del relevador.</p><p>Una instalación adecuada asegura una medición correcta de la corriente.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es ajustar incorrectamente la corriente. Siempre configura según la placa del motor.</p><p>No omitas la protección de sobrecarga durante la operación.</p><p>Permite que el motor se enfríe antes de reiniciar después de un disparo.</p><p>Verifica el cableado correcto del relevador en el circuito de control.</p><p>Prueba la protección durante el comisionamiento para asegurar su correcto funcionamiento.</p>',45)])])}const h=a(n,[["render",c]]);export{m as __pageData,h as default};
